  const [showSearchDropdown, setShowSearchDropdown] = useState(false)
  const [activeTab, setActiveTab] = useState<'keywords' | 'journals'>('keywords')

  const [keywordGroups, setKeywordGroups] = useState<KeywordGroup[]>(DEMO_KEYWORD_GROUPS)
  const [journals, setJournals] = useState<JournalItem[]>(DEMO_JOURNALS)
