  const [searchQuery, setSearchQuery] = useState('')
  const [selectedSearchSite, setSelectedSearchSite] = useState<SearchSite>(SEARCH_SITES[0])
  const [showSearchDropdown, setShowSearchDropdown] = useState(false)
  const [activeTab, setActiveTab] = useState<'keywords' | 'journals'>('keywords')

