  const [journals, setJournals] = useState<JournalItem[]>(DEMO_JOURNALS)
  const [newKeyword, setNewKeyword] = useState('')
  const [newJournal, setNewJournal] = useState('')
  const [editingGroup, setEditingGroup] = useState<string | null>(null)
  const [editName, setEditName] = useState('')

  const handleAddByDoi = async () => {
    const result = normalizeDoi(doiInput)
    if (!result.valid || !result.doi) {
      toast.error('请输入有效的 DOI 或 DOI 链接')
      return
    }
    setIsAdding(true)
    try {
      const { entries, failed } = await getCitationEntries([result.doi])
      if (failed.length > 0) {
        toast.error('DOI 解析失败，请检查输入')
        return
      }
      const meta = entries[0]
      toast.success(`已入库：${meta.title.slice(0, 40)}${meta.title.length > 40 ? '...' : ''}`)
      setDoiInput('')
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err)
      toast.error(`入库失败：${msg}`)
    } finally {
      setIsAdding(false)
    }
  }

  const handleSearch = () => {
    if (!searchQuery.trim()) return
    const url = `${selectedSearchSite.url}?${selectedSearchSite.queryParam}=${encodeURIComponent(searchQuery)}`
    window.open(url, '_blank')
  }

  const addKeywordGroup = () => {
    if (!newKeyword.trim()) {
      toast.error('请输入关键词组名称')
      return
    }
    const newGroup: KeywordGroup = {
      id: Date.now().toString(),
      name: newKeyword.trim(),
      keywords: [],
      enabled: true,
    }
    setKeywordGroups([...keywordGroups, newGroup])
    setNewKeyword('')
    toast.success('已添加关键词组')
  }

  const deleteKeywordGroup = (id: string) => {
    setKeywordGroups(keywordGroups.filter(g => g.id !== id))
    toast.success('已删除关键词组')
  }

  const toggleKeywordGroup = (id: string) => {
    setKeywordGroups(keywordGroups.map(g => g.id === id ? { ...g, enabled: !g.enabled } : g))
  }

  const startEditGroup = (group: KeywordGroup) => {
    setEditingGroup(group.id)
    setEditName(group.name)
  }

  const saveEditGroup = (id: string) => {
    if (!editName.trim()) return
    setKeywordGroups(keywordGroups.map(g => g.id === id ? { ...g, name: editName.trim() } : g))
    setEditingGroup(null)
    toast.success('已更新名称')
  }

