interface KeywordGroup {
  id: string
  name: string
  keywords: string[]
  enabled: boolean
}

interface JournalItem {
  id: string
  name: string
  issn?: string
  enabled: boolean
}

interface SearchSite {
  id: string
  name: string
  url: string
  queryParam: string
  icon: typeof BookOpen
  color: string
}

const SEARCH_SITES: SearchSite[] = [
  { id: 'xmoor', name: 'X-MOL', url: 'https://www.x-mol.com/paper/search', queryParam: 'q', icon: Globe, color: 'bg-blue-50 text-blue-600' },
  { id: 'cnki', name: '中国知网', url: 'https://kns.cnki.net/kns8s/defaultresult/index', queryParam: 'kw', icon: BookOpen, color: 'bg-red-50 text-red-600' },
  { id: 'wanfang', name: '万方数据', url: 'https://s.wanfangdata.com.cn/paper', queryParam: 'q', icon: BookMarked, color: 'bg-orange-50 text-orange-600' },
  { id: 'scholar', name: 'Google Scholar', url: 'https://scholar.google.com/scholar', queryParam: 'q', icon: BookOpen, color: 'bg-slate-50 text-slate-600' },
  { id: 'pubmed', name: 'PubMed', url: 'https://pubmed.ncbi.nlm.nih.gov/', queryParam: 'term', icon: Globe, color: 'bg-indigo-50 text-indigo-600' },
  { id: 'arxiv', name: 'arXiv', url: 'https://arxiv.org/search/', queryParam: 'query', icon: Globe, color: 'bg-slate-100 text-slate-600' },
]

const TRACKING_SOURCES = [
  { label: 'CrossRef', count: 3, color: 'text-indigo-600' },
  { label: 'OpenAlex', count: 2, color: 'text-emerald-600' },
  { label: 'arXiv', count: 1, color: 'text-amber-600' },
  { label: '期刊', count: 2, color: 'text-purple-600' },
]

